9	// TestEscalatableStatusesMatchAgentVocab guards against drift between
10	// agent's ExecuteBeadStatus* constants and escalation.EscalatableStatuses.
11	// If you rename a status in execute_bead_status.go, update both places.
12	func TestEscalatableStatusesMatchAgentVocab(t *testing.T) {
13		expected := map[string]bool{
14			ExecuteBeadStatusExecutionFailed:      true,
15			ExecuteBeadStatusPostRunCheckFailed:   true,
16			ExecuteBeadStatusLandConflict:         true,
17			ExecuteBeadStatusReviewRequestChanges: true,
18			ExecuteBeadStatusReviewBlock:          true,
19		}
20		for status := range expected {
21			if !escalation.EscalatableStatuses[status] {
22				t.Errorf("agent escalatable status %q is not in escalation.EscalatableStatuses", status)
23			}
24		}
25		for status := range escalation.EscalatableStatuses {
26			if !expected[status] {
27				t.Errorf("escalation.EscalatableStatuses has %q not in agent's expected set", status)
28			}
29		}
30		// SuccessStatus alignment
31		if escalation.SuccessStatus != ExecuteBeadStatusSuccess {
32			t.Errorf("escalation.SuccessStatus = %q, want %q (ExecuteBeadStatusSuccess)",
33				escalation.SuccessStatus, ExecuteBeadStatusSuccess)
34		}
35	}
