92	// TestRunReviewFinding tests the review-finding dispatcher.
93	func TestRunReviewFinding(t *testing.T) {
94		ctx := context.Background()
95		mock := newMockBeadEventAppender()
96		now := func() time.Time { return time.Date(2026, 5, 21, 10, 0, 0, 0, time.UTC) }
97	
98		// Create a review-finding bead with payload.
99		reviewBead := &bead.Bead{
100			ID:        "review-001",

100			ID:        "review-001",
101			Title:     "Review Finding",
102			IssueType: bead.IssueTypeReviewFinding,
103			Status:    bead.StatusOpen,
104			Parent:    "parent-001",
105			CreatedAt: now(),
106			UpdatedAt: now(),
107			Extra: map[string]any{
108				"payload": map[string]interface{}{
109					"verdict":     "REQUEST_CHANGES",
110					"findings":    "Found issues in code",
111					"result_rev":  "abc123",
112					"reviewed_by": "alice",
113				},
114			},
115		}
116	
117		report, err := runReviewFinding(ctx, reviewBead.ID, reviewBead, mock, "/tmp", "ddx", now)
118		if err != nil {
119			t.Fatalf("runReviewFinding: %v", err)
120		}
121	
122		if report.Status != ExecuteBeadStatusSuccess {
123			t.Errorf("expected status=success, got %s", report.Status)
124		}
125		if report.Error != "" {
126			t.Errorf("expected no error, got %s", report.Error)
127		}
128	
129		// Verify event was appended.
130		events, ok := mock.events[reviewBead.ID]
131		if !ok || len(events) == 0 {
132			t.Fatalf("expected event to be appended, got none")
133		}
134		if events[0].Kind != "system-review-finding" {
135			t.Errorf("expected kind=system-review-finding, got %s", events[0].Kind)
136		}
137	}
