185	// TestSystemKindDispatcher tests the dispatcher routing.
186	func TestSystemKindDispatcher(t *testing.T) {
187		ctx := context.Background()
188		mock := newMockBeadEventAppender()
189		now := func() time.Time { return time.Date(2026, 5, 21, 10, 0, 0, 0, time.UTC) }
190	
191		// Test review-finding dispatch.
192		reviewBead := &bead.Bead{
193			ID:        "review-002",
194			IssueType: bead.IssueTypeReviewFinding,
195			Parent:    "parent-002",
196			CreatedAt: now(),
197			UpdatedAt: now(),
198			Extra: map[string]any{
