25		}
26	
27		if b == nil {
28			report.Status = ExecuteBeadStatusExecutionFailed
29			report.Error = "bead not found"
30			return report, nil
31		}
32	
33		// Extract payload from bead Extra.
34		payload, err := extractReviewFindingPayload(b)
35		if err != nil {
36			report.Status = ExecuteBeadStatusExecutionFailed
37			report.Error = fmt.Sprintf("extract payload: %v", err)
38			return report, nil
