48			CreatedAt: now().UTC(),
49		}
50	
51		if err := store.AppendEvent(beadID, evt); err != nil {
52			report.Status = ExecuteBeadStatusExecutionFailed
53			report.Error = fmt.Sprintf("append event: %v", err)
54			return report, nil
55		}
56	
57		report.Detail = fmt.Sprintf("Review findings recorded: %s from %s", payload.Verdict, payload.ReviewedBy)
58		return report, nil
59	}
