111	// extractReviewFindingPayload extracts a ReviewFindingPayload from a bead's Extra field.
112	func extractReviewFindingPayload(b *bead.Bead) (*bead.ReviewFindingPayload, error) {
113		if b == nil || b.Extra == nil {
114			return nil, fmt.Errorf("bead or extra is nil")
115		}
116	
117		payloadData, ok := b.Extra["payload"]
118		if !ok {
119			return nil, fmt.Errorf("payload not found in bead extra")
120		}
121	
122		// Type assertion from map[string]interface{} (JSON unmarshaling result).
123		payloadMap, ok := payloadData.(map[string]interface{})
124		if !ok {
125			return nil, fmt.Errorf("payload has unexpected type: %T", payloadData)
126		}
127	
128		payload := &bead.ReviewFindingPayload{}
129	
130		if v, ok := payloadMap["verdict"]; ok {
131			if s, ok := v.(string); ok {
132				payload.Verdict = s
133			}
134		}
135		if v, ok := payloadMap["findings"]; ok {
136			if s, ok := v.(string); ok {
137				payload.Findings = s
138			}
139		}
140		if v, ok := payloadMap["result_rev"]; ok {
141			if s, ok := v.(string); ok {
142				payload.ResultRev = s
143			}
144		}
145		if v, ok := payloadMap["reviewed_by"]; ok {
146			if s, ok := v.(string); ok {
147				payload.ReviewedBy = s
148			}
149		}
150	
151		return payload, nil
152	}
