192	// systemKindDispatcher dispatches system-generated kinds (review-finding, alignment-review).
193	// Returns true if the bead kind was handled by this dispatcher.
194	func systemKindDispatcher(
195		ctx context.Context,
196		beadID string,
197		b *bead.Bead,
198		store ExecuteBeadLoopStore,
199		projectRoot string,
200		assignee string,
201		now func() time.Time,
202	) (ExecuteBeadReport, bool, error) {
203		if b == nil || b.IssueType == "" {
204			return ExecuteBeadReport{}, false, nil
205		}
206	
207		switch b.IssueType {
208		case bead.IssueTypeReviewFinding:
209			report, err := runReviewFinding(ctx, beadID, b, store, projectRoot, assignee, now)
210			return report, true, err
211		case bead.IssueTypeAlignmentReview:
212			report, err := runAlignmentReview(ctx, beadID, b, store, projectRoot, assignee, now)
213			return report, true, err
214		default:
215			return ExecuteBeadReport{}, false, nil
216		}
217	}
